exercise.solution:
:root {
  --color-bg: hsl(210, 60%, 97%);
  --color-bg-alt: hsl(270, 50%, 96%);
  --color-primary: #2563eb;
}

.card {
  width: 20rem;
  padding: 2rem;
  border: 1px solid hsl(210, 20%, 85%);
  border-radius: 12px;
  background-color: var(--color-bg);
}

.card__name {
  font-size: 1.375rem;
  font-weight: 700;
  color: var(--color-primary);
  margin: 0 0 0.25rem;
}

.card__role {
  font-size: 0.9rem;
  color: rgba(0, 0, 0, 0.5);
  margin: 0;
}

.card--alt {
  background-color: var(--color-bg-alt);
}
